Author: YASDC, Inc.
Description: "USN: Range Change (V4)"
EventId: 106
Channel: "FileSystem"
Provider: "USNJournalMonitor"
Maps:
  -
    Property: PayloadData1
    PropertyValue: "%targetfilename%"
    Values:
      -
        Name: targetfilename
        Value: "/Event/EventData/Data[2]"
  -
    Property: PayloadData2
    PropertyValue: "%utctime%"
    Values:
      -
        Name: utctime
        Value: "/Event/EventData/Data[3]"
  -
    Property: PayloadData3
    PropertyValue: "%machineguid%"
    Values:
      -
        Name: machineguid
        Value: "/Event/EventData/Data[4]"
  -
    Property: PayloadData4
    PropertyValue: "HW: %hwserial% | VSN: %vsn%"
    Values:
      -
        Name: hwserial
        Value: "/Event/EventData/Data[5]"
      -
        Name: vsn
        Value: "/Event/EventData/Data[6]"
  -
    Property: PayloadData5
    PropertyValue: "VolSerial: %volserial% | Host: %hostname%"
    Values:
      -
        Name: volserial
        Value: "/Event/EventData/Data[7]"
      -
        Name: hostname
        Value: "/Event/EventData/Data[8]"
  -
    Property: PayloadData6
    PropertyValue: "%category% | Reason: %reason% | Usn: %usn% | Jrnl: %journalid%"
    Values:
      -
        Name: category
        Value: "/Event/EventData/Data[11]"
      -
        Name: reason
        Value: "/Event/EventData/Data[12]"
      -
        Name: usn
        Value: "/Event/EventData/Data[13]"
      -
        Name: journalid
        Value: "/Event/EventData/Data[14]"
